  const BOLETIM_INFORMATIVO_HTML_BASE64 = '';
  const HORARIO_INTEGRADO_HTML_BASE64 = '';
  let boletimIntegradoInicializado = false;
  let horarioIntegradoInicializado = false;
  let ultimoHashBoletimEnviado = '';
  let ultimoHashHorarioEnviado = '';
  let ultimoHashComunicadosEnviado = '';
  let ultimoHashBoletimRecebido = '';
  let ultimoHashHorarioRecebido = '';

  function decodificarHtmlIntegrado(base64) {
    return decodeURIComponent(escape(window.atob(base64)));
  }

  function prepararHtmlHorarioIntegrado(base64) {
    return decodificarHtmlIntegrado(base64)
      .replace(
        "localStorage.setItem('interfaceTheme', currentTheme);",
        "localStorage.setItem('interfaceTheme', currentTheme); syncHorarioDbWithParent('Atualização do tema do módulo de horários');"
      );
  }

  function serializarSeguro(valor) {
    try {
      return JSON.stringify(valor ?? null);
    } catch {
      return '';
    }
  }

  function inicializarBoletimIntegrado(force = false) {
    const frame = document.getElementById('boletimIntegradoFrame');
    if (!frame) return;
    if (!frame.dataset.bridgeBound) {
      frame.addEventListener('load', () => {
        ultimoHashBoletimEnviado = '';
        ultimoHashComunicadosEnviado = '';
        [120, 420, 900].forEach(delay => {
          setTimeout(() => enviarComunicadosParaBoletim(), delay);
          setTimeout(() => enviarBancoBoletimParaFrame(), delay);
        });
      });
      frame.dataset.bridgeBound = '1';
    }
    if (boletimIntegradoInicializado && !force) {
      [0, 180, 520].forEach(delay => {
        setTimeout(() => enviarComunicadosParaBoletim(), delay);
        setTimeout(() => enviarBancoBoletimParaFrame(), delay);
      });
      return;
    }
    frame.srcdoc = decodificarHtmlIntegrado(BOLETIM_INFORMATIVO_HTML_BASE64);
    boletimIntegradoInicializado = true;
  }

  function inicializarHorarioIntegrado(force = false) {
    const frame = document.getElementById('horarioIntegradoFrame');
    if (!frame) return;
    if (!frame.dataset.bridgeBound) {
      frame.addEventListener('load', () => {
        ultimoHashHorarioEnviado = '';
        [120, 420, 900].forEach(delay => setTimeout(() => enviarBancoHorarioParaFrame(), delay));
      });
      frame.dataset.bridgeBound = '1';
    }
    if (horarioIntegradoInicializado && !force) {
      [0, 180, 520].forEach(delay => setTimeout(() => enviarBancoHorarioParaFrame(), delay));
      return;
    }
    frame.srcdoc = prepararHtmlHorarioIntegrado(HORARIO_INTEGRADO_HTML_BASE64);
    horarioIntegradoInicializado = true;
  }

  function enviarBancoBoletimParaFrame() {
    const frame = document.getElementById('boletimIntegradoFrame');
    if (!frame || !frame.contentWindow) return;
    const payload = {
      type: 'ensps:boletimDbSync',
      db: obterBancoBoletim(),
      comunicados: Array.isArray(comunicadosRegistros) ? comunicadosRegistros : []
    };
    const hash = serializarSeguro(payload);
    if (hash === ultimoHashBoletimEnviado) return;
    ultimoHashBoletimEnviado = hash;
    frame.contentWindow.postMessage(payload, '*');
  }

  function enviarBancoHorarioParaFrame() {
    const frame = document.getElementById('horarioIntegradoFrame');
    if (!frame || !frame.contentWindow) return;
    const payload = {
      type: 'ensps:horarioDbSync',
      db: obterBancoHorario()
    };
    const hash = serializarSeguro(payload);
    if (hash === ultimoHashHorarioEnviado) return;
    ultimoHashHorarioEnviado = hash;
    frame.contentWindow.postMessage(payload, '*');
  }

  function navegarPara(sectionId) {
    document.querySelectorAll('.menu-item').forEach(i => i.classList.remove('active'));
    document.querySelectorAll('.bottom-nav-item').forEach(i => i.classList.remove('active'));
    document.querySelectorAll('.content-section').forEach(s => s.classList.remove('active'));
    document.querySelectorAll('[data-section="' + sectionId + '"]').forEach(i => i.classList.add('active'));
    const section = document.getElementById(sectionId);
    if(section) section.classList.add('active');
    if(sectionId === 'gestor' || sectionId === 'estatisticas') atualizarDashboardGestor();
    if(sectionId === 'backup-central') atualizarResumoBackupCentral();
    if(sectionId === 'admin-sistema') adminAtualizarPainel();
    if(sectionId === 'tab-boletim') {
      inicializarBoletimIntegrado();
      [120, 420, 900].forEach(delay => {
        setTimeout(() => enviarComunicadosParaBoletim(), delay);
        setTimeout(() => enviarBancoBoletimParaFrame(), delay);
      });
    }
    if(sectionId === 'tab-horario') {
      inicializarHorarioIntegrado();
      [120, 420, 900].forEach(delay => setTimeout(() => enviarBancoHorarioParaFrame(), delay));
    }
  }

  document.querySelectorAll('.menu-item, .bottom-nav-item').forEach(item => {
    item.addEventListener('click', function(){
      navegarPara(this.getAttribute('data-section'));
    });
  });

