  window.addEventListener('message', function(event){
    const frame = document.getElementById('boletimIntegradoFrame');
    const data = event.data;
    if (!data || typeof data !== 'object') return;
    const isBoletimMessage = ['boletim:requestComunicados','boletim:upsertComunicado','boletim:deleteComunicado','boletim:requestDb','boletim:syncDb'].includes(data.type);
    const isHorarioMessage = ['horario:requestDb','horario:syncDb'].includes(data.type);
    if (!isBoletimMessage && !isHorarioMessage) return;

    if (data.type === 'boletim:requestComunicados') {
      enviarComunicadosParaBoletim();
      return;
    }

    if (data.type === 'boletim:requestDb') {
      enviarBancoBoletimParaFrame();
      return;
    }

    if (data.type === 'boletim:syncDb') {
      const nextDb = data.db && typeof data.db === 'object' ? data.db : obterBancoBoletim();
      const nextHash = serializarSeguro(nextDb);
      const currentHash = serializarSeguro(obterBancoBoletim());
      if (!nextHash || nextHash === currentHash || nextHash === ultimoHashBoletimRecebido) return;
      ultimoHashBoletimRecebido = nextHash;
      enspsDB.boletimInformativo = nextDb;
      persistirENSPSDB({ reason: data.reason || 'Atualização do boletim informativo integrado', remote: false, markDirty: true });
      if (remotoInicializado) salvarEscopoRemoto('boletim', nextDb, { force: true, reason: data.reason || 'Atualização do boletim informativo integrado', silent: true });
      return;
    }

    if (data.type === 'boletim:upsertComunicado' && data.comunicado) {
      const comunicado = data.comunicado;
      const idx = comunicadosRegistros.findIndex(item => String(item.id) === String(comunicado.id));
      const agora = new Date().toISOString();
      const registro = {
        ...(idx >= 0 ? comunicadosRegistros[idx] : {}),
        ...comunicado,
        titulo: comunicado.titulo || comunicado.title || 'Sem título',
        publico: comunicado.publico || comunicado.audience || '',
        texto: comunicado.texto || comunicado.body || '',
        data: comunicado.data || (Array.isArray(comunicado.dates) ? comunicado.dates[0] || '' : ''),
        categoria: comunicado.categoria || 'Boletim Informativo',
        updatedAt: agora,
        createdAt: (idx >= 0 ? comunicadosRegistros[idx].createdAt : comunicado.createdAt) || agora
      };
      if (idx >= 0) comunicadosRegistros[idx] = registro;
      else comunicadosRegistros.push(registro);
      salvarComunicadosRegistros();
      renderComunicadosLista();
      return;
    }

    if (data.type === 'boletim:deleteComunicado' && data.id) {
      comunicadosRegistros = comunicadosRegistros.filter(item => String(item.id) !== String(data.id));
      if (comunicadoAtualId && String(comunicadoAtualId) === String(data.id)) comunicadosLimparFormulario();
      salvarComunicadosRegistros();
      renderComunicadosLista();
      return;
    }

    if (data.type === 'horario:requestDb') {
      enviarBancoHorarioParaFrame();
      return;
    }

    if (data.type === 'horario:syncDb') {
      const nextDb = {
        ...obterBancoHorario(),
        ...(data.db && typeof data.db === 'object' ? data.db : {})
      };
      const nextHash = serializarSeguro(nextDb);
      const currentHash = serializarSeguro(obterBancoHorario());
      if (!nextHash || nextHash === currentHash || nextHash === ultimoHashHorarioRecebido) return;
      ultimoHashHorarioRecebido = nextHash;
      enspsDB.horarios = nextDb;
      persistirENSPSDB({ reason: data.reason || 'Atualização do módulo de horários', remote: false, markDirty: true });
      if (remotoInicializado) salvarEscopoRemoto('horarios', nextDb, { force: true, reason: data.reason || 'Atualização do módulo de horários', silent: true });
    }
  });


