    // Preencher datalists
    function preencheListaAlunos(){
      const lists = ['alunosList', 'alunosListRelatorio', 'alunosListHist', 'alunosListGestor'];
      alunosDB.sort((a,b)=>a.nome.localeCompare(b.nome));

      lists.forEach(listId => {
        const datalist = document.getElementById(listId);
        if(!datalist) return;
        datalist.innerHTML = '';
        alunosDB.forEach(aluno => {
          const opt = document.createElement('option');
          opt.value = aluno.nome;
          datalist.appendChild(opt);
        });
      });
    }
    preencheListaAlunos();

    // =========================
    // BANCO UNIFICADO
    // =========================
    const ENSPS_DB_KEY = 'ensps_db';
    const REMOTE_DB_ENDPOINT = '/api/db';
    let remotoDisponivel = false;
    let remotoInicializado = false;
    let remotoSincronizando = false;
    let remotoUltimoSha = '';
    let remotoUltimoErro = '';
    let remotoTimer = null;
    let remotoMotivoPendente = 'Atualização do sistema';
    let remotoUltimaLeituraEm = 0;
    let remotoPossuiAlteracoesLocaisPendentes = false;

    function lerJSONSeguro(valor, fallback) {
      try {
        return valor ? JSON.parse(valor) : fallback;
      } catch {
        return fallback;
      }
    }

    function coletarLegacyDeliveries() {
      const deliveries = {};
      for (let i = 0; i < localStorage.length; i++) {
        const key = localStorage.key(i);
        if (!key || !key.startsWith('deliveries_')) continue;
        deliveries[key.replace(/^deliveries_/, '')] = lerJSONSeguro(localStorage.getItem(key), {});
      }
      return deliveries;
    }

    function normalizarENSPSDB(origem = {}) {
      const professoresMateriais = origem.professoresMateriais && typeof origem.professoresMateriais === 'object'
        ? origem.professoresMateriais
        : {};
      const professoresFolha = origem.professoresFolha && typeof origem.professoresFolha === 'object'
        ? origem.professoresFolha
        : {};
      return {
        schemaVersion: 2,
        frequenciaAlunos: Array.isArray(origem.frequenciaAlunos) ? origem.frequenciaAlunos : lerJSONSeguro(localStorage.getItem('frequencia'), []),
        advertencias: Array.isArray(origem.advertencias) ? origem.advertencias : lerJSONSeguro(localStorage.getItem('advertencias'), []),
        comunicadosProfessores: Array.isArray(origem.comunicadosProfessores) ? origem.comunicadosProfessores : lerJSONSeguro(localStorage.getItem('comunicados_professores'), []),
        horarios: origem.horarios && typeof origem.horarios === 'object'
          ? {
              scheduleData: origem.horarios.scheduleData && typeof origem.horarios.scheduleData === 'object' ? origem.horarios.scheduleData : {},
              teachersAvailability: origem.horarios.teachersAvailability && typeof origem.horarios.teachersAvailability === 'object' ? origem.horarios.teachersAvailability : {},
              subjectColors: origem.horarios.subjectColors && typeof origem.horarios.subjectColors === 'object' ? origem.horarios.subjectColors : {},
              recentCustomColors: Array.isArray(origem.horarios.recentCustomColors) ? origem.horarios.recentCustomColors : [],
              classTeachingDatabase: origem.horarios.classTeachingDatabase && typeof origem.horarios.classTeachingDatabase === 'object' ? origem.horarios.classTeachingDatabase : {},
              currentGridLineColor: origem.horarios.currentGridLineColor || '#000000',
              currentGridFrameEnabled: Boolean(origem.horarios.currentGridFrameEnabled),
              currentIntervalColor: origem.horarios.currentIntervalColor || '#ffc107',
              currentIntervalFontColor: origem.horarios.currentIntervalFontColor || '#000000',
              currentIntervalText: typeof origem.horarios.currentIntervalText === 'string' ? origem.horarios.currentIntervalText : '',
              currentHeaderBarColor: origem.horarios.currentHeaderBarColor || '#667eea',
              currentHeaderBarFontColor: origem.horarios.currentHeaderBarFontColor || '#ffffff',
              currentTheme: origem.horarios.currentTheme === 'dark' ? 'dark' : 'light'
            }
          : {},
        boletimInformativo: origem.boletimInformativo && typeof origem.boletimInformativo === 'object'
          ? origem.boletimInformativo
          : (
              origem.calendars && Array.isArray(origem.calendars)
                ? {
                    version: origem.version || 2,
                    activeCalendarId: origem.activeCalendarId || origem.calendars[0]?.id || 'ensps-2026',
                    calendars: origem.calendars,
                    ui: origem.ui && typeof origem.ui === 'object' ? origem.ui : { footerLogo: null }
                  }
                : null
            ),
        professoresMateriais: {
          deliveries: professoresMateriais.deliveries && typeof professoresMateriais.deliveries === 'object'
            ? professoresMateriais.deliveries
            : coletarLegacyDeliveries()
        },
        professoresFolha: {
          frequencyRecords: Array.isArray(professoresFolha.frequencyRecords)
            ? professoresFolha.frequencyRecords
            : lerJSONSeguro(localStorage.getItem('frequencyRecords'), []),
          extraAvulsaRecords: professoresFolha.extraAvulsaRecords && typeof professoresFolha.extraAvulsaRecords === 'object'
            ? professoresFolha.extraAvulsaRecords
            : lerJSONSeguro(localStorage.getItem('extraAvulsaRecords'), {})
        }
      };
    }

    function dividirENSPSDBPorEscopo(origem = enspsDB) {
      const db = normalizarENSPSDB(origem);
      return {
        core: {
          schemaVersion: db.schemaVersion || 2,
          frequenciaAlunos: Array.isArray(db.frequenciaAlunos) ? db.frequenciaAlunos : [],
          advertencias: Array.isArray(db.advertencias) ? db.advertencias : [],
          comunicadosProfessores: Array.isArray(db.comunicadosProfessores) ? db.comunicadosProfessores : [],
          professoresMateriais: db.professoresMateriais && typeof db.professoresMateriais === 'object'
            ? db.professoresMateriais
            : { deliveries: {} },
          professoresFolha: db.professoresFolha && typeof db.professoresFolha === 'object'
            ? db.professoresFolha
            : { frequencyRecords: [], extraAvulsaRecords: {} }
        },
        horarios: db.horarios && typeof db.horarios === 'object' ? db.horarios : {},
        boletim: typeof db.boletimInformativo === 'undefined' ? null : db.boletimInformativo
      };
    }

    function carregarENSPSDB() {
      const bruto = localStorage.getItem(ENSPS_DB_KEY);
      if (typeof bruto === 'string' && bruto.length > 900000) {
        console.warn('ENSPS: cache local muito grande, ignorando leitura pesada para preservar a interface.');
        return normalizarENSPSDB({});
      }
      const atual = lerJSONSeguro(bruto, {}) || {};
      return normalizarENSPSDB(atual);
    }

    let enspsDB = carregarENSPSDB();

    function atualizarStatusBancoRemoto(texto, tipo = 'neutro') {
      const el = document.getElementById('backup-remote-status');
      if (!el) return;
      const estilos = {
        neutro: {
          background: 'var(--surface)',
          border: 'var(--border)',
          color: 'var(--muted)'
        },
        ok: {
          background: 'var(--success-dim)',
          border: 'rgba(16,185,129,.35)',
          color: '#86efac'
        },
        aviso: {
          background: 'var(--warning-dim)',
          border: 'rgba(245,158,11,.35)',
          color: '#fcd34d'
        },
        erro: {
          background: 'var(--danger-dim)',
          border: 'rgba(239,68,68,.35)',
          color: '#fca5a5'
        }
      };
      const estilo = estilos[tipo] || estilos.neutro;
      el.textContent = texto;
      el.style.background = estilo.background;
      el.style.borderColor = estilo.border;
      el.style.color = estilo.color;
    }

    function aplicarENSPSDBNaTela() {
      registrosFrequencia = Array.isArray(enspsDB.frequenciaAlunos) ? enspsDB.frequenciaAlunos : [];
      advertenciasSalvas = Array.isArray(enspsDB.advertencias) ? enspsDB.advertencias : [];
      comunicadosRegistros = Array.isArray(enspsDB.comunicadosProfessores) ? enspsDB.comunicadosProfessores : [];
      persistirENSPSDB({ remote: false, markDirty: false });

      if (typeof renderTabelaFrequencia === 'function') renderTabelaFrequencia();
      if (typeof atualizarFaltasAcumuladas === 'function') atualizarFaltasAcumuladas();
      if (typeof renderPendenciasAssinatura === 'function') renderPendenciasAssinatura();
      if (typeof renderComunicadosLista === 'function') renderComunicadosLista();
      if (typeof atualizarResumoBackupCentral === 'function') atualizarResumoBackupCentral();
      if (typeof atualizarDashboardGestor === 'function') atualizarDashboardGestor();
    }

    function criarCacheLocalLeveENSPSDB() {
      return {
        schemaVersion: enspsDB.schemaVersion || 2,
        frequenciaAlunos: Array.isArray(enspsDB.frequenciaAlunos) ? enspsDB.frequenciaAlunos : [],
        advertencias: Array.isArray(enspsDB.advertencias) ? enspsDB.advertencias : [],
        comunicadosProfessores: Array.isArray(enspsDB.comunicadosProfessores) ? enspsDB.comunicadosProfessores : [],
        horarios: {
          teachersAvailability: enspsDB.horarios && typeof enspsDB.horarios.teachersAvailability === 'object' ? enspsDB.horarios.teachersAvailability : {},
          subjectColors: enspsDB.horarios && typeof enspsDB.horarios.subjectColors === 'object' ? enspsDB.horarios.subjectColors : {},
          recentCustomColors: enspsDB.horarios && Array.isArray(enspsDB.horarios.recentCustomColors) ? enspsDB.horarios.recentCustomColors : [],
          classTeachingDatabase: enspsDB.horarios && typeof enspsDB.horarios.classTeachingDatabase === 'object' ? enspsDB.horarios.classTeachingDatabase : {},
          currentGridLineColor: enspsDB.horarios?.currentGridLineColor || '#000000',
          currentGridFrameEnabled: Boolean(enspsDB.horarios?.currentGridFrameEnabled),
          currentIntervalColor: enspsDB.horarios?.currentIntervalColor || '#ffc107',
          currentIntervalFontColor: enspsDB.horarios?.currentIntervalFontColor || '#000000',
          currentIntervalText: typeof enspsDB.horarios?.currentIntervalText === 'string' ? enspsDB.horarios.currentIntervalText : '',
          currentHeaderBarColor: enspsDB.horarios?.currentHeaderBarColor || '#667eea',
          currentHeaderBarFontColor: enspsDB.horarios?.currentHeaderBarFontColor || '#ffffff',
          currentTheme: enspsDB.horarios?.currentTheme === 'dark' ? 'dark' : 'light'
        },
        boletimInformativo: null,
        professoresMateriais: enspsDB.professoresMateriais && typeof enspsDB.professoresMateriais === 'object' ? enspsDB.professoresMateriais : { deliveries: {} },
        professoresFolha: enspsDB.professoresFolha && typeof enspsDB.professoresFolha === 'object' ? enspsDB.professoresFolha : { frequencyRecords: [], extraAvulsaRecords: {} }
      };
    }

    function criarCacheLocalMinimoENSPSDB() {
      return {
        schemaVersion: enspsDB.schemaVersion || 2,
        frequenciaAlunos: [],
        advertencias: [],
        comunicadosProfessores: [],
        horarios: {
          currentTheme: enspsDB.horarios?.currentTheme === 'dark' ? 'dark' : 'light'
        },
        boletimInformativo: null,
        professoresMateriais: { deliveries: {} },
        professoresFolha: { frequencyRecords: [], extraAvulsaRecords: {} }
      };
    }

    function tentarPersistirENSPSDBNoCache(payload) {
      const bruto = JSON.stringify(payload);
      try {
        localStorage.setItem(ENSPS_DB_KEY, bruto);
        return true;
      } catch (erro) {
        if (erro && (erro.name === 'QuotaExceededError' || erro.name === 'NS_ERROR_DOM_QUOTA_REACHED')) {
          try {
            localStorage.removeItem(ENSPS_DB_KEY);
            localStorage.setItem(ENSPS_DB_KEY, bruto);
            return true;
          } catch (erroSecundario) {
            return false;
          }
        }
        throw erro;
      }
    }

    function persistirENSPSDB(options = {}) {
      const { markDirty = null } = options;
      try {
        if (!tentarPersistirENSPSDBNoCache(enspsDB)) {
          if (tentarPersistirENSPSDBNoCache(criarCacheLocalLeveENSPSDB())) {
            console.warn('ENSPS: banco grande demais para localStorage, usando cache local reduzido.');
          } else if (tentarPersistirENSPSDBNoCache(criarCacheLocalMinimoENSPSDB())) {
            console.warn('ENSPS: cache local reduzido ainda excedia a cota; usando cache minimo temporario.');
          } else {
            localStorage.removeItem(ENSPS_DB_KEY);
            console.warn('ENSPS: localStorage sem espaco suficiente; seguindo sem cache local do banco unificado.');
          }
        }
      } catch (erro) {
        console.warn('ENSPS: não foi possível persistir o banco localmente.', erro);
      }
      if (markDirty === true) remotoPossuiAlteracoesLocaisPendentes = true;
      if (markDirty === false) remotoPossuiAlteracoesLocaisPendentes = false;
      if (options.remote !== false) agendarPersistenciaRemota(options.reason || 'Atualização do sistema');
    }

    function sincronizarBancoPrincipal(reason = 'Atualização do sistema') {
      enspsDB.frequenciaAlunos = registrosFrequencia;
      enspsDB.advertencias = advertenciasSalvas;
      enspsDB.comunicadosProfessores = comunicadosRegistros;
      persistirENSPSDB({ reason, markDirty: true });
    }

    function obterDeliveriesMateriais() {
      if (!enspsDB.professoresMateriais || typeof enspsDB.professoresMateriais !== 'object') enspsDB.professoresMateriais = { deliveries: {} };
      if (!enspsDB.professoresMateriais.deliveries || typeof enspsDB.professoresMateriais.deliveries !== 'object') enspsDB.professoresMateriais.deliveries = {};
      return enspsDB.professoresMateriais.deliveries;
    }

    function obterFolhaProfessores() {
      if (!enspsDB.professoresFolha || typeof enspsDB.professoresFolha !== 'object') {
        enspsDB.professoresFolha = { frequencyRecords: [], extraAvulsaRecords: {} };
      }
      if (!Array.isArray(enspsDB.professoresFolha.frequencyRecords)) enspsDB.professoresFolha.frequencyRecords = [];
      if (!enspsDB.professoresFolha.extraAvulsaRecords || typeof enspsDB.professoresFolha.extraAvulsaRecords !== 'object') enspsDB.professoresFolha.extraAvulsaRecords = {};
      return enspsDB.professoresFolha;
    }

    function obterBancoHorario() {
      if (!enspsDB.horarios || typeof enspsDB.horarios !== 'object') enspsDB.horarios = {};
      if (!enspsDB.horarios.scheduleData || typeof enspsDB.horarios.scheduleData !== 'object') enspsDB.horarios.scheduleData = {};
      if (!enspsDB.horarios.teachersAvailability || typeof enspsDB.horarios.teachersAvailability !== 'object') enspsDB.horarios.teachersAvailability = {};
      if (!enspsDB.horarios.subjectColors || typeof enspsDB.horarios.subjectColors !== 'object') enspsDB.horarios.subjectColors = {};
      if (!Array.isArray(enspsDB.horarios.recentCustomColors)) enspsDB.horarios.recentCustomColors = [];
      if (!enspsDB.horarios.classTeachingDatabase || typeof enspsDB.horarios.classTeachingDatabase !== 'object') enspsDB.horarios.classTeachingDatabase = {};
      if (!enspsDB.horarios.currentGridLineColor) enspsDB.horarios.currentGridLineColor = '#000000';
      if (typeof enspsDB.horarios.currentGridFrameEnabled !== 'boolean') enspsDB.horarios.currentGridFrameEnabled = false;
      if (!enspsDB.horarios.currentIntervalColor) enspsDB.horarios.currentIntervalColor = '#ffc107';
      if (!enspsDB.horarios.currentIntervalFontColor) enspsDB.horarios.currentIntervalFontColor = '#000000';
      if (typeof enspsDB.horarios.currentIntervalText !== 'string') enspsDB.horarios.currentIntervalText = '';
      if (!enspsDB.horarios.currentHeaderBarColor) enspsDB.horarios.currentHeaderBarColor = '#667eea';
      if (!enspsDB.horarios.currentHeaderBarFontColor) enspsDB.horarios.currentHeaderBarFontColor = '#ffffff';
      if (enspsDB.horarios.currentTheme !== 'dark' && enspsDB.horarios.currentTheme !== 'light') enspsDB.horarios.currentTheme = 'light';
      return enspsDB.horarios;
    }

    function obterBancoBoletim() {
      if (!enspsDB.boletimInformativo || typeof enspsDB.boletimInformativo !== 'object') enspsDB.boletimInformativo = null;
      return enspsDB.boletimInformativo;
    }

    function atualizarResumoBackupCentral() {
      const frequencias = Array.isArray(enspsDB.frequenciaAlunos) ? enspsDB.frequenciaAlunos : [];
      const advertencias = Array.isArray(enspsDB.advertencias) ? enspsDB.advertencias : [];
      const comunicados = Array.isArray(enspsDB.comunicadosProfessores) ? enspsDB.comunicadosProfessores : [];
      const deliveries = obterDeliveriesMateriais();
      const folha = obterFolhaProfessores();
      const totalMateriais = Object.values(deliveries).reduce((acc, professor) => {
        const registros = professor && typeof professor === 'object' ? Object.values(professor) : [];
        return acc + registros.filter(Boolean).length;
      }, 0);
      const totalExtras = Object.values(folha.extraAvulsaRecords || {}).reduce((acc, lista) => {
        return acc + (Array.isArray(lista) ? lista.length : 0);
      }, 0);

      const mapa = {
        'backup-total-frequencias': frequencias.length,
        'backup-total-advertencias': advertencias.length,
        'backup-total-comunicados': comunicados.length,
        'backup-total-materiais': totalMateriais,
        'backup-total-folha': Array.isArray(folha.frequencyRecords) ? folha.frequencyRecords.length : 0,
        'backup-total-extras': totalExtras
      };

      Object.entries(mapa).forEach(([id, valor]) => {
        const el = document.getElementById(id);
        if (el) el.textContent = String(valor);
      });
    }


    const ENSPS_BACKUP_LOG_KEY = 'ensps_backup_log_v1';

    function clonarJSONSeguro(valor) {
      return JSON.parse(JSON.stringify(valor ?? null));
    }

    function consolidarBancoAtualParaBackup() {
      enspsDB.frequenciaAlunos = Array.isArray(registrosFrequencia) ? registrosFrequencia : [];
      enspsDB.advertencias = Array.isArray(advertenciasSalvas) ? advertenciasSalvas : [];
      enspsDB.comunicadosProfessores = Array.isArray(comunicadosRegistros) ? comunicadosRegistros : [];
      enspsDB.professoresMateriais = { deliveries: obterDeliveriesMateriais() };
      enspsDB.professoresFolha = obterFolhaProfessores();
      obterBancoHorario();
      obterBancoBoletim();
      enspsDB = normalizarENSPSDB(enspsDB);
      return enspsDB;
    }

    function contarItensBackup(db = {}) {
      const frequencias = Array.isArray(db.frequenciaAlunos) ? db.frequenciaAlunos : [];
      const advertencias = Array.isArray(db.advertencias) ? db.advertencias : [];
      const comunicados = Array.isArray(db.comunicadosProfessores) ? db.comunicadosProfessores : [];
      const deliveries = db.professoresMateriais && db.professoresMateriais.deliveries && typeof db.professoresMateriais.deliveries === 'object'
        ? db.professoresMateriais.deliveries
        : {};
      const folha = db.professoresFolha && typeof db.professoresFolha === 'object'
        ? db.professoresFolha
        : { frequencyRecords: [], extraAvulsaRecords: {} };
      const totalMateriais = Object.values(deliveries).reduce((acc, professor) => {
        const registros = professor && typeof professor === 'object' ? Object.values(professor) : [];
        return acc + registros.filter(Boolean).length;
      }, 0);
      const totalExtras = Object.values(folha.extraAvulsaRecords || {}).reduce((acc, lista) => acc + (Array.isArray(lista) ? lista.length : 0), 0);
      return {
        frequencias: frequencias.length,
        advertencias: advertencias.length,
        comunicados: comunicados.length,
        materiais: totalMateriais,
        folhaProfessores: Array.isArray(folha.frequencyRecords) ? folha.frequencyRecords.length : 0,
        extrasAvulsas: totalExtras,
        horarios: db.horarios && typeof db.horarios === 'object' ? Object.keys(db.horarios.scheduleData || {}).length : 0,
        temBoletim: Boolean(db.boletimInformativo)
      };
    }

    function formatarResumoBackup(contagens) {
      return [
        `Frequência: ${contagens.frequencias}`,
        `Advertências: ${contagens.advertencias}`,
        `Comunicados: ${contagens.comunicados}`,
        `Materiais: ${contagens.materiais}`,
        `Folha professores: ${contagens.folhaProfessores}`,
        `Extras: ${contagens.extrasAvulsas}`,
        `Horários: ${contagens.horarios}`,
        `Boletim: ${contagens.temBoletim ? 'sim' : 'não'}`
      ].join('\n');
    }

    function nomeArquivoBackup(prefixo = 'backup_ensps_completo') {
      const agora = new Date();
      const stamp = agora.toISOString().replace(/[:.]/g, '-').slice(0, 19);
      return `${prefixo}_${stamp}.json`;
    }

    function montarBackupCompleto(origem = 'manual') {
      const bancoAtual = clonarJSONSeguro(consolidarBancoAtualParaBackup());
      const contagens = contarItensBackup(bancoAtual);
      return {
        tipoArquivo: 'ENSPS_BACKUP_COMPLETO',
        versaoBackup: 3,
        sistema: 'Sistema ENSPS 2026',
        origem,
        criadoEm: new Date().toISOString(),
        resumo: contagens,
        ensps_db: bancoAtual,
        compatibilidade: {
          aceitaBackupsAntigos: true,
          modoRemoto: 'Cloudflare Pages + GitHub split storage'
        }
      };
    }

    function registrarEventoBackup(tipo, detalhes = {}) {
      const payload = {
        tipo,
        data: new Date().toISOString(),
        ...detalhes
      };
      try {
        localStorage.setItem(ENSPS_BACKUP_LOG_KEY, JSON.stringify(payload));
      } catch {}
      atualizarUltimoBackupNaTela(payload);
    }

    function atualizarUltimoBackupNaTela(evento = null) {
      const el = document.getElementById('backup-last-action');
      if (!el) return;
      let payload = evento;
      if (!payload) {
        try { payload = JSON.parse(localStorage.getItem(ENSPS_BACKUP_LOG_KEY) || 'null'); } catch { payload = null; }
      }
      if (!payload) {
        el.textContent = 'Nenhum backup manual registrado neste navegador ainda.';
        return;
      }
      const data = payload.data ? new Date(payload.data).toLocaleString('pt-BR') : 'data não informada';
      const arquivo = payload.arquivo ? ` • Arquivo: ${payload.arquivo}` : '';
      const contagens = payload.resumo ? ` • Frequências: ${payload.resumo.frequencias || 0} • Advertências: ${payload.resumo.advertencias || 0}` : '';
      el.textContent = `Última ação: ${payload.tipo} em ${data}${arquivo}${contagens}`;
    }

    function exportarBackupCompleto(prefixo = 'backup_ensps_completo', origem = 'manual') {
      const backup = montarBackupCompleto(origem);
      const nome = nomeArquivoBackup(prefixo);
      baixarArquivo(JSON.stringify(backup, null, 2), nome, 'application/json');
      registrarEventoBackup('backup exportado', { arquivo: nome, resumo: backup.resumo });
      return { backup, nome };
    }

    function baixarBancoAtualJSON() {
      const bancoAtual = clonarJSONSeguro(consolidarBancoAtualParaBackup());
      const nome = nomeArquivoBackup('ensps_banco_atual');
      baixarArquivo(JSON.stringify(bancoAtual, null, 2), nome, 'application/json');
      registrarEventoBackup('banco atual baixado', { arquivo: nome, resumo: contarItensBackup(bancoAtual) });
    }

    function extrairBancoDeArquivoBackup(backup) {
      if (!backup || typeof backup !== 'object') throw new Error('Arquivo JSON inválido.');
      if (backup.ensps_db && typeof backup.ensps_db === 'object') return normalizarENSPSDB(backup.ensps_db);
      if (backup.tipoArquivo === 'ENSPS_BACKUP_COMPLETO' && backup.ensps_db) return normalizarENSPSDB(backup.ensps_db);
      if (Array.isArray(backup.frequenciaAlunos) || Array.isArray(backup.advertencias) || backup.horarios || backup.boletimInformativo) return normalizarENSPSDB(backup);
      return normalizarENSPSDB({
        ...enspsDB,
        frequenciaAlunos: backup.frequencia || [],
        advertencias: backup.advertencias || [],
        comunicadosProfessores: backup.comunicadosProfessores || [],
        professoresMateriais: backup.professoresMateriais || { deliveries: backup.deliveries || {} },
        professoresFolha: backup.professoresFolha || {
          frequencyRecords: backup.frequencyRecords || [],
          extraAvulsaRecords: backup.extraAvulsaRecords || {}
        },
        horarios: backup.horarios || enspsDB.horarios || {},
        boletimInformativo: Object.prototype.hasOwnProperty.call(backup, 'boletimInformativo') ? backup.boletimInformativo : enspsDB.boletimInformativo
      });
    }

    function aplicarBancoRestaurado(novoBanco) {
      enspsDB = normalizarENSPSDB(novoBanco);
      registrosFrequencia = Array.isArray(enspsDB.frequenciaAlunos) ? enspsDB.frequenciaAlunos : [];
      advertenciasSalvas = Array.isArray(enspsDB.advertencias) ? enspsDB.advertencias : [];
      comunicadosRegistros = Array.isArray(enspsDB.comunicadosProfessores) ? enspsDB.comunicadosProfessores : [];
      persistirENSPSDB({ reason: 'Restauração manual de backup', markDirty: true });
      aplicarENSPSDBNaTela();
      if (typeof renderTabelaSegundaChamadaPorDia === 'function') renderTabelaSegundaChamadaPorDia();
      if (typeof renderRelatorioSegundaChamada === 'function') renderRelatorioSegundaChamada();
      if (typeof enviarBancoHorarioParaFrame === 'function') enviarBancoHorarioParaFrame();
      if (typeof enviarBancoBoletimParaFrame === 'function') enviarBancoBoletimParaFrame();
      setTimeout(alertarPendenciasAssinaturaDiarias, 250);
    }

    function formatarCaminhoRemoto(pathInfo) {
      if (!pathInfo) return '';
      if (typeof pathInfo === 'string') return pathInfo;
      if (typeof pathInfo === 'object') {
        return Object.values(pathInfo).filter(Boolean).join(', ');
      }
      return String(pathInfo);
    }

    function obterShaRemoto(scope = '') {
      if (!scope) return remotoUltimoSha || '';
      if (remotoUltimoSha && typeof remotoUltimoSha === 'object') {
        return typeof remotoUltimoSha[scope] === 'string' ? remotoUltimoSha[scope] : '';
      }
      return '';
    }

    function atualizarShaRemoto(scope = '', sha = '') {
      if (!scope) {
        remotoUltimoSha = sha || '';
        return;
      }
      const mapa = (remotoUltimoSha && typeof remotoUltimoSha === 'object') ? { ...remotoUltimoSha } : {};
      mapa[scope] = sha || '';
      remotoUltimoSha = mapa;
    }

    async function carregarEscopoRemoto(scope) {
      const resposta = await fetch(`${REMOTE_DB_ENDPOINT}?scope=${encodeURIComponent(scope)}`, {
        headers: { 'Accept': 'application/json' }
      });
      if (resposta.status === 404) {
        return {
          scope,
          notFound: true,
          data: scope === 'boletim' ? null : {}
        };
      }
      if (!resposta.ok) throw new Error(`Falha ao consultar API remota (${resposta.status})`);
      const payload = await resposta.json();
      return {
        scope,
        notFound: false,
        data: payload.data,
        sha: payload.sha || '',
        path: payload.path || '',
        fromLegacy: Boolean(payload.fromLegacy)
      };
    }

    async function carregarBancoRemoto() {
      try {
        const resultados = await Promise.all([
          carregarEscopoRemoto('core'),
          carregarEscopoRemoto('horarios'),
          carregarEscopoRemoto('boletim')
        ]);

        if (resultados.every(item => item.notFound)) {
          remotoDisponivel = true;
          remotoUltimoSha = { core: '', horarios: '', boletim: '' };
          atualizarStatusBancoRemoto('GitHub conectado. Ainda não existe arquivo remoto; o próximo salvamento criará o banco na pasta do repositório.', 'aviso');
          return null;
        }

        const shaMap = {};
        resultados.forEach(item => {
          shaMap[item.scope] = item.sha || '';
        });

        const partes = {
          ...(resultados.find(item => item.scope === 'core')?.data || {}),
          horarios: resultados.find(item => item.scope === 'horarios')?.data || {},
          boletimInformativo: resultados.find(item => item.scope === 'boletim')?.data ?? null
        };

        remotoDisponivel = true;
        remotoUltimoSha = shaMap;
        remotoUltimaLeituraEm = Date.now();
        if (!partes || typeof partes !== 'object') {
          atualizarStatusBancoRemoto('GitHub conectado. Arquivo remoto vazio; o banco local será usado até o primeiro envio.', 'aviso');
          return null;
        }
        atualizarStatusBancoRemoto('GitHub conectado. Banco remoto carregado com sucesso.', 'ok');
        return normalizarENSPSDB(partes);
      } catch (erro) {
        remotoDisponivel = false;
        remotoUltimoErro = erro.message || String(erro);
        atualizarStatusBancoRemoto(`Sem conexão com o GitHub agora. O sistema seguirá em modo local temporariamente. Motivo: ${remotoUltimoErro}`, 'erro');
        return null;
      }
    }

    async function salvarBancoRemoto(options = {}) {
      const { force = false, reason = 'Atualização do sistema', silent = true } = options;
      if (!remotoInicializado && !force) return false;
      if (remotoSincronizando) return false;
      remotoSincronizando = true;
      atualizarStatusBancoRemoto('Sincronizando banco com o GitHub...', 'aviso');

      try {
        enspsDB.professoresMateriais = { deliveries: obterDeliveriesMateriais() };
        enspsDB.professoresFolha = obterFolhaProfessores();

        const partes = dividirENSPSDBPorEscopo(enspsDB);
        const escoposParaSalvar = force ? ['core', 'horarios', 'boletim'] : ['core'];
        const shaMap = (remotoUltimoSha && typeof remotoUltimoSha === 'object') ? { ...remotoUltimoSha } : {};
        const pathMap = {};

        for (const scope of escoposParaSalvar) {
          const resposta = await fetch(`${REMOTE_DB_ENDPOINT}?scope=${encodeURIComponent(scope)}`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
              db: partes[scope],
              sha: shaMap[scope] || undefined,
              reason: `${reason} [${scope}]`
            })
          });

          const payload = await resposta.json().catch(() => ({}));
          if (!resposta.ok || !payload.ok) {
            throw new Error(payload.error || `Falha ao salvar ${scope} no GitHub (${resposta.status})`);
          }

          shaMap[scope] = payload.sha || '';
          pathMap[scope] = payload.path || '';
        }

        remotoDisponivel = true;
        remotoUltimoSha = shaMap;
        remotoUltimoErro = '';
        remotoUltimaLeituraEm = Date.now();
        remotoPossuiAlteracoesLocaisPendentes = false;
        const caminhoRemoto = formatarCaminhoRemoto(pathMap);
        atualizarStatusBancoRemoto(`GitHub sincronizado com sucesso. ${caminhoRemoto ? `Arquivo: ${caminhoRemoto}` : ''}`.trim(), 'ok');
        if (!silent) alert('✅ Banco sincronizado com sucesso no GitHub!');
        return true;
      } catch (erro) {
        remotoDisponivel = false;
        remotoUltimoErro = erro.message || String(erro);
        atualizarStatusBancoRemoto(`Não foi possível sincronizar com o GitHub. Os dados continuam salvos localmente. Motivo: ${remotoUltimoErro}`, 'erro');
        if (!silent) alert('❌ Falha ao sincronizar com o GitHub: ' + remotoUltimoErro);
        return false;
      } finally {
        remotoSincronizando = false;
      }
    }

    async function salvarEscopoRemoto(scope, dbEscopo, options = {}) {
      const { force = false, reason = 'Atualização do sistema', silent = true } = options;
      if (!scope) return salvarBancoRemoto({ force, reason, silent });
      if (!remotoInicializado && !force) return false;
      if (remotoSincronizando) return false;
      remotoSincronizando = true;
      atualizarStatusBancoRemoto(`Sincronizando ${scope} com o GitHub...`, 'aviso');

      try {
        const resposta = await fetch(`${REMOTE_DB_ENDPOINT}?scope=${encodeURIComponent(scope)}`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            db: dbEscopo,
            sha: obterShaRemoto(scope) || undefined,
            reason
          })
        });

        const payload = await resposta.json().catch(() => ({}));
        if (!resposta.ok || !payload.ok) {
          throw new Error(payload.error || `Falha ao salvar ${scope} no GitHub (${resposta.status})`);
        }

        remotoDisponivel = true;
        remotoUltimoErro = '';
        remotoUltimaLeituraEm = Date.now();
        atualizarShaRemoto(scope, payload.sha || '');
        remotoPossuiAlteracoesLocaisPendentes = false;
        const caminhoRemoto = formatarCaminhoRemoto(payload.path);
        atualizarStatusBancoRemoto(`GitHub sincronizado com sucesso. ${caminhoRemoto ? `Arquivo: ${caminhoRemoto}` : ''}`.trim(), 'ok');
        if (!silent) alert(`✅ ${scope} sincronizado com sucesso no GitHub!`);
        return true;
      } catch (erro) {
        remotoDisponivel = false;
        remotoUltimoErro = erro.message || String(erro);
        atualizarStatusBancoRemoto(`Não foi possível sincronizar ${scope} com o GitHub. Os dados continuam salvos localmente. Motivo: ${remotoUltimoErro}`, 'erro');
        if (!silent) alert(`❌ Falha ao sincronizar ${scope} com o GitHub: ` + remotoUltimoErro);
        return false;
      } finally {
        remotoSincronizando = false;
      }
    }

    function agendarPersistenciaRemota(reason = 'Atualização do sistema') {
      remotoMotivoPendente = reason;
      if (!remotoInicializado) return;
      if (remotoTimer) clearTimeout(remotoTimer);
      remotoTimer = setTimeout(() => {
        remotoTimer = null;
        salvarBancoRemoto({ reason: remotoMotivoPendente, silent: true });
      }, 1200);
    }

    async function inicializarBancoRemoto() {
      const bancoRemoto = await carregarBancoRemoto();
      remotoInicializado = true;

      if (bancoRemoto) {
        enspsDB = bancoRemoto;
        aplicarENSPSDBNaTela();
        return;
      }

      if (remotoDisponivel) {
        await salvarBancoRemoto({ force: true, reason: 'Migração inicial do banco local para o GitHub', silent: true });
      }
    }

    async function sincronizarBancoRemotoEmSegundoPlano(reason = 'Verificação automática do banco remoto') {
      if (!remotoInicializado || remotoSincronizando) return false;
      if (remotoPossuiAlteracoesLocaisPendentes) {
        atualizarStatusBancoRemoto('Alterações locais ainda não foram confirmadas no GitHub. A sincronização automática vai aguardar para não sobrescrever seus dados.', 'aviso');
        return false;
      }
      const bancoRemoto = await carregarBancoRemoto();
      if (!bancoRemoto) return false;
      const remotoSerializado = JSON.stringify(bancoRemoto);
      const localSerializado = JSON.stringify(normalizarENSPSDB(enspsDB));
      if (remotoSerializado === localSerializado) return false;
      enspsDB = bancoRemoto;
      aplicarENSPSDBNaTela();
      atualizarStatusBancoRemoto(`Banco remoto atualizado no dispositivo. ${reason}`, 'ok');
      return true;
    }

